import React, {useMemo, useState} from 'react'; 
import "./ProductsPage.css"; 


import ProductsList from "/Users/ruslanhincagov/Documents/Fronted Backend 3-4PR/4PR/src/components/ProductsList.jsx";
import ProductModal from "/Users/ruslanhincagov/Documents/Fronted Backend 3-4PR/4PR/src/components/ProductModal.jsx";
import {api} from "/Users/ruslanhincagov/Documents/Fronted Backend 3-4PR/4PR/src/api/index"

export default function ProductsPage() {
    const [products, setProduct] = useState([
        {id: 1, name: "Джерси-футболка casher", price: "3500", category: "Верхняя одежда", description: "Черно-белая", countInStock: 3},
        {id: 2, name: "Джерси casher", price: "6500", category: "Верхняя одежда", description: "Черная", countInStock: 1},
        {id: 3, name: "Шорты casher", price: "4500", category: "Шорты", description: "Бело-зеленые", countInStock: 12},
    ]);

    //  {id: 1, name: "Джерси-футболка casher", price: "3500", category: "Верхняя одежда", description: "Черно-белая", countInStock: 3},
    //  {id: 2, name: "Джерси casher", price: "6500", category: "Верхняя одежда", description: "Черная", countInStock: 1},
    //  {id: 3, name: "Шорты casher", price: "4500", category: "Шорты", description: "Бело-зеленые", countInStock: 12},

    const [modalOpen, setModalOpen] = useState(false);
    const [loading, setLoading] = useState(true);
    const [modalMode, setModalMode] = useState("create");
    const [editingProduct, setEditingProduct] = useState(null);

    useEffect(() => {
        loadProducts();
    }, []);

    const loadProducts = async () => {
        try {
            setLoading(true);
            const data = await api.getProducts();
            setProduct(data);
        } catch (err) {
            console.error(err);
            alert("Ошибка загрузки пользователей");
        } finally {
            setLoading(false);
        }
    };

    const openCreate = () => {
        setModalMode("create");
        setEditingProduct(null);
        setModalOpen(true);
    };

    const openEdit = (user) => {
        setModalMode("edit");
        setEditingProduct(user);
        setModalOpen(true);
    };

    const closeModal = () => {
        setModalOpen(false);
        setEditingProduct(null);
    };

    const handleDelete = (id) => {
        const ok = window.confirm("Удалить товар?");
        if (!ok) return;
        setProduct((prev) => prev.filter((p) => p.id !== id));
    };

    const handleSubmitModal = async (payload) => {
        try {
            if (modalMode === "create") {
                const newProduct = await api.createProduct(payload);
                setProduct((prev) => [ ... prev, newProduct]);
            } else {
                const updatedProduct = await api.updateProduct(payload.id, payload);
                setProduct((prev) =>
                    prev.map((p) => (p.id === payload.id ? updatedProduct : u))
                );
            }
            closeModal();
        } catch (err) {
            console.error(err);
            alert("Ошибка сохранения пользователя");
        }
    }

    return (
        <div className="page">
            <header className="header">
                <div className="header__inner">
                    <div className="brand">Users App</div>
                    <div className="header__right">React</div>
                </div>
            </header>

            <main className="main">
                <div className="container">
                    <div className="toolbar">
                    <h1 className="title">Товары</h1>
                    <button className="btn btn--primary" onClick={openCreate}>
                        + Создать
                    </button>
                </div>

                {loading ? (
                    <div className="empty">Загрузка...</div>
                ) : (
                    <ProductsList products={products} onEdit={openEdit} onDelete={handleDelete} />
                )}

                </div>
            </main>

            <footer className="footer">
                <div className="footer__inner">© {new Date().getFullYear()}Clothes Store App</div>
            </footer>
            <ProductModal open={modalOpen} mode={modalMode} 
                    initialUser={editingUser} 
                    onClose={closeModal} 
                    onSubmit={handleSubmitModal}
            />
        </div>
    );
};
